// // This module converts a 3-bit binary number to its equivalent 3-bit Gray code. The most significant bit remains unchanged, and each lower bit is the result of XORing the current binary bit with the previous one.
module bin2gray (
    input wire [2:0] bin,
    output wire [2:0] gray
);

assign gray[2] = bin[2];
assign gray[1] = bin[2] ^ bin[1];
assign gray[0] = bin[1] ^ bin[0];

endmodule
